SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS `order_items`;
DROP TABLE IF EXISTS `orders`;
DROP TABLE IF EXISTS `customers`;
DROP TABLE IF EXISTS `products`;
DROP TABLE IF EXISTS `categories`;
CREATE TABLE `categories` (`id` BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,`name` VARCHAR(100) NOT NULL,`image` VARCHAR(255) DEFAULT NULL,`created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP,`updated_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `products` (`id` BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,`category_id` BIGINT UNSIGNED NOT NULL,`name` VARCHAR(150) NOT NULL,`description` TEXT DEFAULT NULL,`price` DECIMAL(10,2) NOT NULL,`image` VARCHAR(255) DEFAULT NULL,`stock` INT DEFAULT 0,`is_available` TINYINT(1) DEFAULT 1,`created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP,`updated_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY (`category_id`) REFERENCES `categories`(`id`) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `customers` (`id` BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,`name` VARCHAR(100) NOT NULL,`email` VARCHAR(150) UNIQUE DEFAULT NULL,`phone` VARCHAR(20) DEFAULT NULL,`address` TEXT DEFAULT NULL,`created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP,`updated_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `orders` (`id` BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,`customer_id` BIGINT UNSIGNED DEFAULT NULL,`total_price` DECIMAL(10,2) NOT NULL DEFAULT 0,`status` ENUM('pending','processing','completed','cancelled') DEFAULT 'pending',`note` TEXT DEFAULT NULL,`created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP,`updated_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY (`customer_id`) REFERENCES `customers`(`id`) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `order_items` (`id` BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,`order_id` BIGINT UNSIGNED NOT NULL,`product_id` BIGINT UNSIGNED NOT NULL,`quantity` INT NOT NULL DEFAULT 1,`unit_price` DECIMAL(10,2) NOT NULL,`subtotal` DECIMAL(10,2) AS (`quantity` * `unit_price`) STORED,`created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY (`order_id`) REFERENCES `orders`(`id`) ON DELETE CASCADE,FOREIGN KEY (`product_id`) REFERENCES `products`(`id`) ON DELETE RESTRICT) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
SET FOREIGN_KEY_CHECKS = 1;
